from itertools import combinations

class Solution:
    def minDistinctFreqPair(self, nums):
        # Independent approach: brute force every unordered pair of distinct values
        # directly (no pre-sorted scan), keeping the lexicographically smallest.
        freq = {}
        for v in nums:
            freq[v] = freq.get(v, 0) + 1
        best = None
        for x, y in combinations(sorted(freq.keys()), 2):
            if freq[x] != freq[y]:
                pair = [x, y]
                if best is None or pair < best:
                    best = pair
        return best if best is not None else [-1, -1]

