class Solution:
    def minDistinctFreqPair(self, nums):
        freq = {}
        for v in nums:
            freq[v] = freq.get(v, 0) + 1
        vals = sorted(freq.keys())
        n = len(vals)
        for i in range(n):
            for j in range(i + 1, n):
                if freq[vals[i]] != freq[vals[j]]:
                    return [vals[i], vals[j]]
        return [-1, -1]

