var minDistinctFreqPair = function(nums) {
    const freq = new Map();
    for (const v of nums) {
        freq.set(v, (freq.get(v) || 0) + 1);
    }
    const vals = Array.from(freq.keys()).sort((a, b) => a - b);
    const n = vals.length;
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            if (freq.get(vals[i]) !== freq.get(vals[j])) {
                return [vals[i], vals[j]];
            }
        }
    }
    return [-1, -1];
};
